// ============================================================
// INFO PANEL — aparece solo cuando hay UNA familia seleccionada
// ============================================================
function updateInfoPanel(filtered){
  const panel   = document.getElementById('info-panel');
  const statsPn = document.getElementById('stats-panel');
  const familiaActiva = fFamilia.value;

  // Mostrar info panel solo si hay una familia concreta seleccionada
  if(!familiaActiva){ 
    panel.classList.remove('visible'); 
    // Estadísticas dinámicas
    const centrosUnicos    = new Set(filtered.map(d=>d.centro)).size;
    const familiasUnicas   = new Set(filtered.map(d=>d.familia)).size;
    const municipiosUnicos = new Set(filtered.map(d=>d.municipio)).size;
    statsPn.style.display='block';
    statsPn.querySelector('.stats-cards').innerHTML = `
      <div class="stat-card"><div class="stat-card-num">${centrosUnicos}</div><div class="stat-card-label">${t('statCentres')}</div></div>
      <div class="stat-card"><div class="stat-card-num">${filtered.length}</div><div class="stat-card-label">${t('statCiclesDisp')}</div></div>
      <div class="stat-card"><div class="stat-card-num">${municipiosUnicos}</div><div class="stat-card-label">${t('statMunicipis')}</div></div>
      <div class="stat-card"><div class="stat-card-num">${familiasUnicas}</div><div class="stat-card-label">${t('statFamiliesPro')}</div></div>`;
    return; 
  }

  statsPn.style.display='none';

  const cicloActivo = fCiclo.value || '';
  const nivelActivo = fNivel.value || (filtered.length ? filtered[0].nivel : '');
  const info = cicloActivo ? tCicleInfo(cicloActivo) : {};

  // Descripción: si hay ciclo concreto la mostramos, si solo familia mostramos la de familia
  const descFamilia = tFamDesc(familiaActiva);
  const descMostrar = cicloActivo ? (info.desc||descFamilia) : descFamilia;
  const salidasMostrar = cicloActivo ? (info.salidas||'') : '';
  const tituloMostrar = cicloActivo || familiaActiva;

  document.getElementById('ip-icon').textContent    = familiaEmoji[familiaActiva]||'📁';
  document.getElementById('ip-familia').textContent = tFam(familiaActiva);
  document.getElementById('ip-ciclo').textContent   = currentLang==='val'?(cicleNomVal[tituloMostrar]||famNomVal[tituloMostrar]||tituloMostrar):tituloMostrar;
  document.getElementById('ip-desc').textContent    = descMostrar;
  document.getElementById('ip-salidas').innerHTML   = salidasMostrar ? '<strong>'+t('salidas')+'</strong> '+salidasMostrar : '';

  const nBadge = document.getElementById('ip-nivel-wrap');
  if(nivelActivo && cicloActivo){ 
    var labels = {'FPB':t('fpbLabel'),'GM':t('gmLabel'),'GS':t('gsLabel')};
    nBadge.innerHTML=`<span class="info-nivel-badge ${nivelActivo.toLowerCase()}">${labels[nivelActivo]||nivelActivo}</span>`; 
  } else { nBadge.innerHTML=''; }

  // FPB → GM
  const esFPB = nivelActivo==='FPB';
  const esGM  = nivelActivo==='GM';
  const gmSection = document.getElementById('ip-gm');
  if(esFPB && fpbAGm[familiaActiva]){
    document.getElementById('ip-gm-btns').innerHTML = fpbAGm[familiaActiva].map(function(c){ return mkBtn(familiaActiva,c,'irAGM','#22c55e'); }).join('');
    document.querySelector('#ip-gm .info-gm-title').textContent = t('fpbToGm');
    gmSection.style.display='block';
  } else if(esGM && gmAGs[familiaActiva]){
    document.getElementById('ip-gm-btns').innerHTML = gmAGs[familiaActiva].map(function(c){ return mkBtn(familiaActiva,c,'irAGS','#4f46e5'); }).join('');
    document.querySelector('#ip-gm .info-gm-title').textContent = t('gmToGs');
    gmSection.style.display='block';
  } else { gmSection.style.display='none'; }

  panel.classList.add('visible');
}

function mkBtn(familia, ciclo, fn, color){
  var label = currentLang==='val'?(cicleNomVal[ciclo]||ciclo):ciclo;
  return `<button class="btn-gm" style="background:${color}" data-fn="${fn}" data-familia="${familia.replace(/"/g,'&quot;')}" data-ciclo="${ciclo.replace(/"/g,'&quot;')}">${label}</button>`;
}

// Delegación de eventos para los botones de progresión del info panel
document.getElementById('info-panel').addEventListener('click', function(e){
  var btn = e.target.closest('.btn-gm[data-fn]');
  if(!btn) return;
  var fn = btn.dataset.fn;
  var familia = btn.dataset.familia;
  var ciclo = btn.dataset.ciclo;
  if(fn==='irAGM') irAGM(familia, ciclo);
  else if(fn==='irAGS') irAGS(familia, ciclo);
});
function irAGS(familia, ciclo){
  // Switch to familias tab first
  currentTab='familias';
  document.querySelectorAll('.tab-btn').forEach(b=>b.classList.remove('active'));
  document.getElementById('tab-familias').classList.add('active');
  document.getElementById('map-container').style.display='none';
  document.getElementById('cards-container').style.display='block';
  document.getElementById('fg-familia').style.display='';
  document.getElementById('fg-ciclo').style.display='';
  document.getElementById('fg-centro').style.display='none';
  document.getElementById('fg-tipologia').style.display='none';
  fNivel.value='GS'; fFamilia.value=familia;
  actualizarFiltrosCascada();
  setTimeout(()=>{ fCiclo.value=ciclo; render(); window.scrollTo({top:0,behavior:'smooth'}); }, 60);
}

function irAGM(familia, ciclo){
  currentTab='familias';
  document.querySelectorAll('.tab-btn').forEach(b=>b.classList.remove('active'));
  document.getElementById('tab-familias').classList.add('active');
  document.getElementById('map-container').style.display='none';
  document.getElementById('cards-container').style.display='block';
  document.getElementById('fg-familia').style.display='';
  document.getElementById('fg-ciclo').style.display='';
  document.getElementById('fg-centro').style.display='none';
  document.getElementById('fg-tipologia').style.display='none';
  fNivel.value='GM'; fFamilia.value=familia;
  actualizarFiltrosCascada();
  setTimeout(()=>{ fCiclo.value=ciclo; render(); window.scrollTo({top:0,behavior:'smooth'}); }, 60);
}

